"""matplotlib.artist — base Artist class."""

import numpy as _np


class Artist:
    """Base class for all visual elements."""

    def __init__(self):
        self._alpha = None
        self._visible = True
        self._label = ''
        self._zorder = 0
        self._transform = None
        self._clip_on = True
        self._animated = False
        self._picker = None
        self._rasterized = None
        self._sketch_params = None
        self._path_effects = []
        self._snap = None
        self._stale = True
        self.axes = None
        self.figure = None

    def get_alpha(self): return self._alpha
    def set_alpha(self, a): self._alpha = a
    def get_visible(self): return self._visible
    def set_visible(self, v): self._visible = v
    def get_label(self): return self._label
    def set_label(self, l): self._label = str(l)
    def get_zorder(self): return self._zorder
    def set_zorder(self, z): self._zorder = z
    def get_transform(self): return self._transform
    def set_transform(self, t): self._transform = t
    def get_clip_on(self): return self._clip_on
    def set_clip_on(self, b): self._clip_on = b
    def get_clip_box(self): return None
    def set_clip_box(self, box): pass
    def get_clip_path(self): return None
    def set_clip_path(self, path, transform=None): pass
    def get_animated(self): return self._animated
    def set_animated(self, b): self._animated = b
    def get_picker(self): return self._picker
    def set_picker(self, p): self._picker = p
    def get_rasterized(self): return self._rasterized
    def set_rasterized(self, r): self._rasterized = r
    def get_sketch_params(self): return self._sketch_params
    def set_sketch_params(self, scale=None, length=None, randomness=None):
        self._sketch_params = (scale, length, randomness)
    def get_path_effects(self): return self._path_effects
    def set_path_effects(self, effects): self._path_effects = effects
    def get_snap(self): return self._snap
    def set_snap(self, snap): self._snap = snap
    def get_figure(self): return self.figure
    def set_figure(self, fig): self.figure = fig
    def get_axes(self): return self.axes
    def get_children(self): return []
    def contains(self, mouseevent): return False, {}
    def pick(self, mouseevent): pass
    def pchanged(self): pass
    def remove(self): pass
    def stale_callback(self, *args): pass
    def findobj(self, match=None, include_self=True): return []
    def get_window_extent(self, renderer=None): return None
    def set(self, **kwargs):
        for k, v in kwargs.items():
            setter = getattr(self, f'set_{k}', None)
            if setter:
                setter(v)
    def update(self, props):
        if isinstance(props, dict):
            self.set(**props)
    def properties(self):
        return {}
    def update_from(self, other): pass
    def draw(self, renderer): pass
    def get_agg_filter(self): return None
    def set_agg_filter(self, f): pass
    def get_gid(self): return None
    def set_gid(self, gid): pass
    def get_url(self): return None
    def set_url(self, url): pass


def getp(obj, property=None):
    """Get property (or all properties) of an artist."""
    if property:
        return getattr(obj, f'get_{property}', lambda: None)()
    return {}


def setp(obj, *args, **kwargs):
    """Set properties on an artist."""
    if isinstance(obj, (list, tuple)):
        for o in obj:
            setp(o, *args, **kwargs)
        return
    if hasattr(obj, 'set'):
        obj.set(**kwargs)


def get(obj, *args, **kwargs):
    return getp(obj, *args, **kwargs)


class ArtistInspector:
    def __init__(self, o):
        self.o = o
    def get_aliases(self):
        return {}
    def get_setters(self):
        return []
    def get_valid_values(self, attr):
        return ''
